```C [sol1-C]
typedef struct {
    int key;
    int val;
    UT_hash_handle hh;
} HashItem; 

HashItem *hashFindItem(HashItem **obj, int key) {
    HashItem *pEntry = NULL;
    HASH_FIND_INT(*obj, &key, pEntry);
    return pEntry;
}

bool hashAddItem(HashItem **obj, int key, int val) {
    if (hashFindItem(obj, key)) {
        return false;
    }
    HashItem *pEntry = (HashItem *)malloc(sizeof(HashItem));
    pEntry->key = key;
    pEntry->val = val;
    HASH_ADD_INT(*obj, key, pEntry);
    return true;
}

bool hashSetItem(HashItem **obj, int key, int val) {
    HashItem *pEntry = hashFindItem(obj, key);
    if (!pEntry) {
        hashAddItem(obj, key, val);
    } else {
        pEntry->val = val;
    }
    return true;
}

int hashGetItem(HashItem **obj, int key, int defaultVal) {
    HashItem *pEntry = hashFindItem(obj, key);
    if (!pEntry) {
        return defaultVal;
    }
    return pEntry->val;
}

void hashFree(HashItem **obj) {
    HashItem *curr = NULL, *tmp = NULL;
    HASH_ITER(hh, *obj, curr, tmp) {
        HASH_DEL(*obj, curr);  
        free(curr);
    }
}

static int compare(const void *a, const void *b) {
    return *(int *)b - *(int *)a;
}

int minSetSize(int* arr, int arrSize) {
    HashItem *freq = NULL;
    for (int i = 0; i < arrSize; i++) {
        hashSetItem(&freq, arr[i], hashGetItem(&freq, arr[i], 0) + 1);
    }

    int occSize = HASH_COUNT(freq);
    int *occ = (int *)calloc(occSize, sizeof(int));
    int pos = 0;
    for (HashItem *pEntry = freq; pEntry; pEntry = pEntry->hh.next) {
        occ[pos++] = pEntry->val;
    }
    qsort(occ, occSize, sizeof(int), compare);
    int cnt = 0, ans = 0;
    for (int i = 0; i < occSize; ++i) {
        cnt += occ[i];
        ans++;
        if (cnt * 2 >= arrSize) {
            break;
        }
    }
    hashFree(&freq);
    return ans;
}
```

